import React, { useRef, useEffect } from 'react';
import './ChatInput.css';

const SUGGESTIONS = [
  'Which airline has the highest average fare?',
  'Show bookings by class (Economy, Business, First)',
  'What is the cancellation rate per airline?',
  'Top 5 routes by number of bookings',
  'Average duration by number of layovers',
  'Monthly booking trend for 2023',
  'Revenue breakdown by extras type',
  'Which terminal has the most departures?',
];

export default function ChatInput({ input, setInput, onSend, isLoading, onCancel }) {
  const textareaRef = useRef(null);

  useEffect(() => {
    if (textareaRef.current) {
      textareaRef.current.style.height = 'auto';
      textareaRef.current.style.height = Math.min(textareaRef.current.scrollHeight, 140) + 'px';
    }
  }, [input]);

  const handleKeyDown = (e) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      onSend(input);
    }
  };

  return (
    <div className="chat-input-area">
      {/* Suggestion chips */}
      <div className="suggestions-row">
        {SUGGESTIONS.map((s, i) => (
          <button
            key={i}
            className="suggestion-chip"
            onClick={() => onSend(s)}
            disabled={isLoading}
          >
            {s}
          </button>
        ))}
      </div>

      {/* Input bar */}
      <div className="input-bar">
        <div className="input-prefix">
          <span className="prompt-symbol">›</span>
        </div>

        <textarea
          ref={textareaRef}
          className="chat-textarea"
          placeholder="Ask anything about the flight data…  (Enter to send, Shift+Enter for new line)"
          value={input}
          onChange={e => setInput(e.target.value)}
          onKeyDown={handleKeyDown}
          disabled={isLoading}
          rows={1}
        />

        <div className="input-actions">
          {isLoading ? (
            <button className="send-btn cancel" onClick={onCancel} title="Cancel">
              <span className="spinner" />
              CANCEL
            </button>
          ) : (
            <button
              className="send-btn"
              onClick={() => onSend(input)}
              disabled={!input.trim()}
              title="Send (Enter)"
            >
              SEND
              <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5">
                <line x1="22" y1="2" x2="11" y2="13"/>
                <polygon points="22 2 15 22 11 13 2 9 22 2"/>
              </svg>
            </button>
          )}
        </div>
      </div>

      <div className="input-footer">
        <span>FLIGHTIQ · Powered by GPT-4o-mini + pandas</span>
        <span>Shift+Enter for new line</span>
      </div>
    </div>
  );
}
